from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about astronauts (or related entities) into a
    fluent English sentence. The function now builds more coherent
    multi‑triple sentences, especially for mission/crew relationships and
    nationality.
    """
    if not triples:
        return ""

    # Clean object string
    def clean_obj(o: str) -> str:
        return o.strip().strip('"')

    # Helper to format ISO dates nicely
    def fmt_date(d: str) -> str:
        try:
            from datetime import datetime
            dt = datetime.strptime(d, "%Y-%m-%d")
            return dt.strftime("%B %-d, %Y")
        except Exception:
            return d

    # ------------------------------------------------------------------
    # Gather special structures: missions ↔ crew members
    # ------------------------------------------------------------------
    mission_to_crew: dict[str, list[str]] = {}
    astronaut_to_mission: dict[str, str] = {}

    for t in triples:
        pred = t.predicate.lower().replace(" ", "")
        if pred == "crewmembers":
            mission = t.subject
            crew = clean_obj(t.object)
            mission_to_crew.setdefault(mission, []).append(crew)
        elif pred == "mission":
            astronaut = t.subject
            mission = clean_obj(t.object)
            astronaut_to_mission[astronaut] = mission

    # ------------------------------------------------------------------
    # Phrase builder for single predicate/object pairs
    # ------------------------------------------------------------------
    def phrase(subj: str, pred: str, obj: str) -> str:
        obj = clean_obj(obj)
        p = pred.lower().replace(" ", "")

        if p == "birthdate":
            return f"{subj} was born on {fmt_date(obj)}"
        if p == "birthplace":
            return f"{subj} was born in {obj}"
        if p == "deathdate":
            return f"{subj} died on {fmt_date(obj)}"
        if p == "deathplace":
            return f"{subj} died in {obj}"
        if p == "nationality":
            # More natural expression
            return f"{subj} was a citizen of {obj}"
        if p == "occupation":
            return f"{subj} was a {obj}"
        if p == "status":
            obj_clean = obj.lower()
            return f"{subj} is {obj_clean}"
        if p == "selectedbynasa":
            return f"{subj} was selected by NASA in {obj}"
        if p == "timeinspace":
            try:
                mins = float(obj)
                hrs = int(mins // 60)
                rem = int(mins % 60)
                if hrs:
                    return f"{subj} spent {hrs} hour{'s' if hrs>1 else ''}" + (f" and {rem} minute{'s' if rem!=1 else ''}" if rem else "") + " in space"
                else:
                    return f"{subj} spent {rem} minute{'s' if rem!=1 else ''} in space"
            except Exception:
                return f"{subj} spent {obj} minutes in space"
        if p == "title":
            return f"{subj} held the title of {obj}"
        if p == "award":
            return f"{subj} received the {obj}"
        if p == "awards":
            return f"{subj} received {obj} awards"
        if p == "ribbonaward":
            return f"{subj} was awarded the {obj}"
        if p == "operator":
            return f"{subj} was operated by {obj}"
        if p == "commander":
            return f"{obj} was the commander of {subj}"
        if p == "backuppilot":
            return f"{subj}'s backup pilot was {obj}"
        if p == "alternativename":
            return f"{subj} is also known as {obj}"
        if p == "servedaschiefoftheastronautofficein":
            return f"{subj} served as Chief of the Astronaut Office in {obj}"
        if p == "representative":
            return f"{obj} was the representative of {subj}"
        if p == "bird":
            return f"The {obj} is the state bird of {subj}"
        # Generic fallback
        return f"{subj} {pred} {obj}"

    # ------------------------------------------------------------------
    # Build sentences
    # ------------------------------------------------------------------
    sentences: list[str] = []

    # 1. Handle mission‑crew combined sentences first
    handled_missions = set()
    for mission, crew_list in mission_to_crew.items():
        # Astronauts that have this mission via the "mission" predicate
        astronauts = [a for a, m in astronaut_to_mission.items() if m == mission]
        all_astronauts = list(dict.fromkeys(astronauts + crew_list))  # preserve order, dedupe
        if len(all_astronauts) == 1:
            sent = f"{all_astronauts[0]} was a crew member of {mission}"
        else:
            # Build a natural list with commas and "and"
            if len(all_astronauts) == 2:
                names = f"{all_astronauts[0]} and {all_astronauts[1]}"
            else:
                names = ", ".join(all_astronauts[:-1]) + f", and {all_astronauts[-1]}"
            sent = f"{names} were crew members of {mission}"
        sentences.append(sent)
        handled_missions.add(mission)

    # 2. Process remaining triples (those not part of the mission‑crew grouping)
    from collections import defaultdict
    groups = defaultdict(list)
    for t in triples:
        # Skip triples already used in the mission‑crew grouping
        if t.predicate.lower().replace(" ", "") == "crewmembers" and t.subject in handled_missions:
            continue
        if t.predicate.lower().replace(" ", "") == "mission" and t.subject in astronaut_to_mission and astronaut_to_mission[t.subject] in handled_missions:
            continue
        groups[t.subject].append(t)

    for subj, items in groups.items():
        parts = [phrase(subj, t.predicate, t.object) for t in items]
        if len(parts) == 1:
            sent = parts[0]
        else:
            sent = ", ".join(parts[:-1]) + ", and " + parts[-1]
        sentences.append(sent)

    # Combine all sentences into final output
    return " Also, ".join(sentences) + "."

# EVOLVE-BLOCK-END

